                Sandbox[(Sandbox<br>File System & Shell)];
                HierarchicalActionSpace -- "Level 2: Utilities" --> Sandbox;
                HierarchicalActionSpace -- "Level 3: Dynamic Code/APIs" --> Sandbox;
